import { createHmac } from "crypto";
function hashIp(ip) {
  const secret = process.env["IP_HASH_SECRET"];
  if (!secret) throw new Error("IP_HASH_SECRET is required");
  return createHmac("sha256", secret).update(ip).digest("hex");
}
function rateLimitMiddleware(limiter, getIdentifier) {
  return createMiddleware(async (c3, next) => {
    const identifier = getIdentifier(c3);
    try {
      const { success, limit, remaining, reset } = await limiter.limit(identifier);
      c3.header("X-RateLimit-Limit", String(limit));
      c3.header("X-RateLimit-Remaining", String(remaining));
      c3.header("X-RateLimit-Reset", String(reset));
      if (!success) {
        return c3.json({ error: "Rate limit exceeded. Please try again later." }, 429);
      }
    } catch {
    }
    await next();
  });
}
function ipHashIdentifier(c3) {
  const ip = c3.req.header("x-forwarded-for")?.split(",")[0]?.trim() ?? c3.req.header("x-real-ip") ?? "unknown";
  return hashIp(ip);
}

