function matchFaq(question, language) {
  const fuse = language === "nl" ? fuseNl : fuseEn;
  const results = fuse.search(question);
  if (results.length === 0) return null;
  const best = results[0];
  return {
    entry: best.item,
    score: 1 - (best.score ?? 1)
    // convert to 0=worst, 1=perfect
  };
}

// src/api/routes/chat.ts
var chatRoutes = new Hono2();
chatRoutes.post("/", zValidator("json", ChatRequestSchema), async (c3) => {
  const { message, language } = c3.req.valid("json");
  const user = c3.get("user");
  const ipHash = ipHashIdentifier(c3);
  const identifier = user?.id ?? ipHash;
  const limiter = user ? rateLimits.chatAuth : rateLimits.chatAnon;
  const { success } = await limiter.limit(identifier);
  if (!success) {
    return c3.json({ error: "Rate limit exceeded \u2014 try again tomorrow" }, 429);
  }
  const today = (/* @__PURE__ */ new Date()).toISOString().slice(0, 10);
  const existingSession = await db.select().from(chatbotSessions).where(and(eq(chatbotSessions.ipHash, ipHash), eq(chatbotSessions.date, today))).then((rows) => rows[0]);
  if (existingSession) {
    await db.update(chatbotSessions).set({ messagesToday: existingSession.messagesToday + 1 }).where(eq(chatbotSessions.id, existingSession.id));
  } else {
    await db.insert(chatbotSessions).values({
      ipHash,
      userId: user?.id ?? null,
      messagesToday: 1,
      date: today
    });
  }
  const faqMatch = matchFaq(message, language);
  if (faqMatch !== null) {
    const answer = language === "nl" ? faqMatch.entry.answer_nl : faqMatch.entry.answer_en;
    return c3.json({
      answer,
      source: "faq",
      faqId: faqMatch.entry.id
    });
  }
  const safe = sanitiseForPrompt(message);
  const aiResponse = await generateAIResponse({
    systemPrompt: CHAT_SYSTEM(language),
    prompt: CHAT_PROMPT(safe),
    language
  });
  await db.insert(unansweredQuestions).values({ question: message.slice(0, 500), language });
  return c3.json({ answer: aiResponse.text, source: "ai" });
});

